from pathlib import Path
import re, shutil, sys

TARGET = Path(sys.argv[1]) if len(sys.argv) > 1 else Path('app.py')

IMPORTS = '''\ntry:\n    from reportlab.lib import colors\n    from reportlab.lib.pagesizes import A4\n    from reportlab.lib.styles import getSampleStyleSheet\n    from reportlab.lib.units import mm\n    from reportlab.platypus import SimpleDocTemplate, Paragraph, Spacer, Table, TableStyle\n    REPORTLAB_AVAILABLE = True\nexcept ImportError:\n    REPORTLAB_AVAILABLE = False\n'''

HELPERS = '''\n# ---------------- Guest billing documents ----------------\ndef migrate_guest_billing():\n    with conn() as c:\n        c.executescript(\"\"\"\n        CREATE TABLE IF NOT EXISTS guest_receipts(\n            receipt_no TEXT PRIMARY KEY, receipt_date TEXT, reservation_id TEXT,\n            guest_name TEXT, room_no TEXT, receipt_type TEXT, payment_method TEXT,\n            payment_reference TEXT, amount REAL, received_by TEXT, created_at TEXT\n        );\n        CREATE TABLE IF NOT EXISTS guest_invoices(\n            invoice_no TEXT PRIMARY KEY, invoice_date TEXT, reservation_id TEXT,\n            guest_name TEXT, room_no TEXT, room_amount REAL, restaurant_amount REAL,\n            other_amount REAL, subtotal REAL, vat_amount REAL, gross_amount REAL,\n            deposit_amount REAL, final_payment REAL, balance_due REAL,\n            payment_method TEXT, payment_reference TEXT, status TEXT, created_by TEXT,\n            created_at TEXT\n        );\n        \"\"\")\n        c.commit()\n\nmigrate_guest_billing()\n\ndef _pdf(value):\n    return str(value if value is not None else '').replace('&','&amp;').replace('<','&lt;').replace('>','&gt;')\n\ndef build_receipt_pdf(r):\n    if not REPORTLAB_AVAILABLE:\n        return None\n    b=BytesIO(); styles=getSampleStyleSheet()\n    doc=SimpleDocTemplate(b,pagesize=A4,rightMargin=18*mm,leftMargin=18*mm,topMargin=15*mm,bottomMargin=15*mm)\n    story=[Paragraph('HOTEL CONTROL TOWER',styles['Title']),Paragraph('ADVANCE PAYMENT RECEIPT',styles['Heading2']),Spacer(1,6*mm)]\n    data=[['Receipt No',r['receipt_no'],'Date',r['receipt_date']],['Reservation',r['reservation_id'],'Room',r['room_no']],['Guest',r['guest_name'],'Method',r['payment_method']],['Reference',r['payment_reference'] or '-','Amount',money(r['amount'])],['Received By',r['received_by'],'Type',r['receipt_type']]]\n    t=Table(data,colWidths=[32*mm,55*mm,30*mm,55*mm]); t.setStyle(TableStyle([('GRID',(0,0),(-1,-1),.5,colors.grey),('BACKGROUND',(0,0),(0,-1),colors.HexColor('#eff6ff')),('BACKGROUND',(2,0),(2,-1),colors.HexColor('#eff6ff')),('FONTNAME',(0,0),(0,-1),'Helvetica-Bold'),('FONTNAME',(2,0),(2,-1),'Helvetica-Bold'),('PADDING',(0,0),(-1,-1),7)])); story.append(t); story.append(Spacer(1,12*mm)); story.append(Paragraph('Received with thanks from <b>'+_pdf(r['guest_name'])+'</b> the amount of <b>'+_pdf(money(r['amount']))+'</b>.',styles['BodyText'])); doc.build(story); b.seek(0); return b.getvalue()\n\ndef build_invoice_pdf(i,s):\n    if not REPORTLAB_AVAILABLE:\n        return None\n    b=BytesIO(); styles=getSampleStyleSheet()\n    doc=SimpleDocTemplate(b,pagesize=A4,rightMargin=18*mm,leftMargin=18*mm,topMargin=15*mm,bottomMargin=15*mm)\n    story=[Paragraph('HOTEL CONTROL TOWER',styles['Title']),Paragraph('FINAL GUEST TAX INVOICE',styles['Heading2']),Spacer(1,5*mm)]\n    info=[['Invoice',i['invoice_no'],'Date',i['invoice_date']],['Guest',s['guest_name'],'Reservation',s['reservation_id']],['Room',s['room_no'],'Stay',str(s['checkin_date'])+' to '+str(s['checkout_date'])]]\n    t=Table(info,colWidths=[28*mm,58*mm,28*mm,58*mm]); t.setStyle(TableStyle([('GRID',(0,0),(-1,-1),.5,colors.grey),('BACKGROUND',(0,0),(0,-1),colors.HexColor('#f8fafc')),('BACKGROUND',(2,0),(2,-1),colors.HexColor('#f8fafc')),('FONTNAME',(0,0),(0,-1),'Helvetica-Bold'),('FONTNAME',(2,0),(2,-1),'Helvetica-Bold'),('PADDING',(0,0),(-1,-1),7)])); story.extend([t,Spacer(1,7*mm)])\n    lines=[['Description','Amount (SAR)'],['Room Charges',f\"{i['room_amount']:,.2f}\"],['Restaurant / Room Service',f\"{i['restaurant_amount']:,.2f}\"],['Other Charges',f\"{i['other_amount']:,.2f}\"],['Subtotal',f\"{i['subtotal']:,.2f}\"],['VAT 15%',f\"{i['vat_amount']:,.2f}\"],['Gross Amount',f\"{i['gross_amount']:,.2f}\"],['Less: Advance',f\"({i['deposit_amount']:,.2f})\"],['Final Payment',f\"{i['final_payment']:,.2f}\"],['Balance Due',f\"{i['balance_due']:,.2f}\"]]\n    lt=Table(lines,colWidths=[125*mm,45*mm]); lt.setStyle(TableStyle([('GRID',(0,0),(-1,-1),.5,colors.grey),('BACKGROUND',(0,0),(-1,0),colors.HexColor('#1d4ed8')),('TEXTCOLOR',(0,0),(-1,0),colors.white),('FONTNAME',(0,0),(-1,0),'Helvetica-Bold'),('ALIGN',(1,1),(1,-1),'RIGHT'),('PADDING',(0,0),(-1,-1),7)])); story.extend([lt,Spacer(1,7*mm),Paragraph('Payment Method: <b>'+_pdf(i['payment_method'])+'</b> &nbsp;&nbsp; Reference: <b>'+_pdf(i['payment_reference'] or '-')+'</b>',styles['BodyText'])]); doc.build(story); b.seek(0); return b.getvalue()\n'''

FRONT = '''# ---------------- Front Desk ----------------\nelif page == "Front Desk":\n    st.title("Front Desk Operations")\n    st.caption("Check-in, advance receipt, room transfer, folio and final invoice.")\n    reserved_df=query("SELECT * FROM reservations WHERE status='Reserved' ORDER BY checkin_date, room_no")\n    checked_df=query("SELECT * FROM reservations WHERE status='Checked-in' ORDER BY room_no")\n    ready_df=query("SELECT room_no,room_type,rate,housekeeping FROM rooms WHERE status='Available' AND LOWER(COALESCE(housekeeping,'')) IN ('clean','ready') ORDER BY room_no")\n    t1,t2,t3,t4=st.tabs(["🛎️ Check-in & Advance Receipt","🔁 Room Transfer","🧾 Guest Folio","✅ Check-out & Invoice"])\n\n    with t1:\n        if reserved_df.empty: st.info("No pending arrivals.")\n        else:\n            labels={r['reservation_id']:f\"{r['reservation_id']} | {r['guest_name']} | Room {r['room_no']}\" for _,r in reserved_df.iterrows()}\n            rid=st.selectbox("Select Arrival",reserved_df['reservation_id'].tolist(),format_func=lambda x:labels.get(x,x),key='arrive')\n            row=reserved_df[reserved_df['reservation_id']==rid].iloc[0]; room=str(row['room_no']); old_deposit=float(row['deposit'] or 0)\n            c1,c2,c3,c4=st.columns(4); c1.metric('Guest',str(row['guest_name'])); c2.metric('Room',room); c3.metric('Arrival',str(row['checkin_date'])); c4.metric('Advance',money(old_deposit))\n            hk=str(scalar("SELECT housekeeping FROM rooms WHERE room_no=?",(room,),'Unknown')); ready=hk.strip().lower() in {'clean','ready'}\n            if not ready:\n                st.error(f"Room {room} is not ready. Housekeeping status: {hk}")\n                if not ready_df.empty:\n                    nr=st.selectbox('Assign another clean room',ready_df['room_no'].astype(str).tolist(),key='pre_room')\n                    if st.button('Assign New Room',type='primary',use_container_width=True):\n                        execute("UPDATE reservations SET room_no=? WHERE reservation_id=?",(nr,rid)); execute("UPDATE rooms SET status='Available' WHERE room_no=?",(room,)); execute("UPDATE rooms SET status='Reserved' WHERE room_no=?",(nr,)); st.success(f"Reservation moved from room {room} to {nr}."); st.rerun()\n            else: st.success(f"Room {room} is ready.")\n            st.markdown('#### Advance payment at check-in')\n            a1,a2,a3=st.columns(3); adv=a1.number_input('Advance received now (SAR)',min_value=0.0,value=0.0,step=50.0,key=f'adv_{rid}'); method=a2.selectbox('Payment method',['Cash','MADA','Visa','Mastercard','AMEX','Bank Transfer','Online'],key=f'am_{rid}'); ref=a3.text_input('Payment reference',key=f'ar_{rid}')\n            verify=st.checkbox('Guest identity and reservation details verified',key=f'v_{rid}')\n            if st.button('Check-in Guest and Create Receipt',type='primary',disabled=(not verify or not ready),use_container_width=True,key=f'ci_{rid}'):\n                total=old_deposit+float(adv); execute("UPDATE reservations SET status='Checked-in',deposit=? WHERE reservation_id=?",(total,rid)); execute("UPDATE rooms SET status='Occupied' WHERE room_no=?",(room,))\n                if adv>0:\n                    rno=next_code('RCP','guest_receipts'); execute("INSERT INTO guest_receipts VALUES(?,?,?,?,?,?,?,?,?,?,?)",(rno,str(date.today()),rid,str(row['guest_name']),room,'Advance Payment',method,ref.strip(),float(adv),user['full_name'],datetime.now().isoformat(timespec='seconds'))); execute("INSERT INTO payments(payment_id,payment_date,reference,customer,payment_method,amount,payment_type) VALUES(?,?,?,?,?,?,?)",(next_code('PAY','payments'),str(date.today()),ref.strip() or rno,str(row['guest_name']),method,float(adv),'Guest Advance')); st.session_state['latest_receipt']=rno\n                st.success('Guest checked in successfully.'); st.rerun()\n            receipts=query("SELECT * FROM guest_receipts WHERE reservation_id=? ORDER BY created_at DESC",(rid,))\n            if not receipts.empty:\n                rr=receipts.iloc[0].to_dict(); pdf=build_receipt_pdf(rr); st.dataframe(receipts,use_container_width=True,hide_index=True)\n                if pdf: st.download_button('🖨️ Print / Download Advance Receipt',pdf,f\"{rr['receipt_no']}_Advance_Receipt.pdf\",'application/pdf',use_container_width=True)\n                else: st.error('Install reportlab: pip install reportlab')\n\n    with t2:\n        if checked_df.empty or ready_df.empty: st.info('Checked-in guest and clean available room are required.')\n        else:\n            tr=st.selectbox('Guest Reservation',checked_df['reservation_id'].tolist(),key='tr'); old=str(checked_df[checked_df['reservation_id']==tr].iloc[0]['room_no']); nr=st.selectbox('New Room',ready_df['room_no'].astype(str).tolist(),key='nr')\n            if st.button('Transfer Room',type='primary',use_container_width=True): execute("UPDATE reservations SET room_no=? WHERE reservation_id=?",(nr,tr)); execute("UPDATE rooms SET status='Available',housekeeping='Dirty' WHERE room_no=?",(old,)); execute("UPDATE rooms SET status='Occupied' WHERE room_no=?",(nr,)); st.success(f'Guest transferred from {old} to {nr}.'); st.rerun()\n\n    with t3:\n        fol=query("SELECT * FROM reservations WHERE status IN ('Checked-in','Checked-out') ORDER BY created_at DESC")\n        if fol.empty: st.info('No guest folios.')\n        else:\n            frid=st.selectbox('Select Folio',fol['reservation_id'].tolist(),key='folio'); fr=fol[fol['reservation_id']==frid].iloc[0]; nights=max((pd.to_datetime(fr['checkout_date']).date()-pd.to_datetime(fr['checkin_date']).date()).days,1); room_amt=nights*float(fr['room_rate'] or 0); rest=float(scalar("SELECT COALESCE(SUM(amount),0) FROM orders WHERE order_type='Room Service' AND table_room=? AND COALESCE(payment_status,'')!='Paid'",(str(fr['room_no']),),0)); dep=float(fr['deposit'] or 0); sub=room_amt+rest; vat=sub*.15; gross=sub+vat; bal=gross-dep\n            c1,c2,c3,c4=st.columns(4); c1.metric('Room',money(room_amt)); c2.metric('Restaurant',money(rest)); c3.metric('Advance',money(dep)); c4.metric('Balance',money(bal)); st.dataframe(pd.DataFrame([['Room Charges',room_amt],['Restaurant / Room Service',rest],['Subtotal',sub],['VAT 15%',vat],['Gross Amount',gross],['Less: Advance',-dep],['Balance Due',bal]],columns=['Description','Amount']),use_container_width=True,hide_index=True)\n\n    with t4:\n        checked_df=query("SELECT * FROM reservations WHERE status='Checked-in' ORDER BY checkout_date, room_no")\n        if checked_df.empty: st.info('No checked-in guests available for check-out.')\n        else:\n            coid=st.selectbox('Select Departure',checked_df['reservation_id'].tolist(),key='co'); co=checked_df[checked_df['reservation_id']==coid].iloc[0]; room=str(co['room_no']); nights=max((pd.to_datetime(co['checkout_date']).date()-pd.to_datetime(co['checkin_date']).date()).days,1); room_amt=nights*float(co['room_rate'] or 0); rest=float(scalar("SELECT COALESCE(SUM(amount),0) FROM orders WHERE order_type='Room Service' AND table_room=? AND COALESCE(payment_status,'')!='Paid'",(room,),0)); other=st.number_input('Other charges (SAR)',min_value=0.0,value=0.0,step=10.0,key=f'oth_{coid}'); sub=room_amt+rest+float(other); vat=sub*.15; gross=sub+vat; dep=float(co['deposit'] or 0); due=max(gross-dep,0)\n            c1,c2,c3,c4=st.columns(4); c1.metric('Gross',money(gross)); c2.metric('Advance',money(dep)); c3.metric('Balance Due',money(due)); c4.metric('Nights',nights)\n            p1,p2,p3=st.columns(3); final=p1.number_input('Final payment received (SAR)',min_value=0.0,value=float(due),step=50.0,key=f'fp_{coid}'); pm=p2.selectbox('Payment method',['Cash','MADA','Visa','Mastercard','AMEX','Bank Transfer','Online','Corporate Credit'],key=f'pm_{coid}'); pref=p3.text_input('Payment reference',key=f'pr_{coid}'); bal=round(gross-dep-float(final),2)\n            if abs(bal)<=.01: st.success('Folio is fully settled.')\n            elif bal>0: st.error(f'Outstanding balance: {money(bal)}. Check-out is blocked.')\n            else: st.warning(f'Overpayment / refund due: {money(abs(bal))}')\n            ok=st.checkbox('Confirm folio, payment and departure details',key=f'ok_{coid}')\n            if st.button('Complete Check-out and Generate Invoice',type='primary',disabled=(not ok or abs(bal)>.01),use_container_width=True,key=f'done_{coid}'):\n                ino=next_code('INV','guest_invoices'); now=datetime.now().isoformat(timespec='seconds'); execute("INSERT INTO guest_invoices VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)",(ino,str(date.today()),coid,str(co['guest_name']),room,room_amt,rest,float(other),sub,vat,gross,dep,float(final),bal,pm,pref.strip(),'Paid',user['full_name'],now))\n                if final>0: execute("INSERT INTO payments(payment_id,payment_date,reference,customer,payment_method,amount,payment_type) VALUES(?,?,?,?,?,?,?)",(next_code('PAY','payments'),str(date.today()),pref.strip() or ino,str(co['guest_name']),pm,float(final),'Guest Final Settlement'))\n                execute("UPDATE reservations SET status='Checked-out' WHERE reservation_id=?",(coid,)); execute("UPDATE rooms SET status='Available',housekeeping='Dirty' WHERE room_no=?",(room,)); execute("UPDATE orders SET payment_status='Paid' WHERE order_type='Room Service' AND table_room=?",(room,)); st.session_state['latest_invoice']=ino; st.success(f'Check-out completed. Invoice {ino} generated.'); st.rerun()\n        ino=st.session_state.get('latest_invoice')\n        if ino:\n            ii=query("SELECT * FROM guest_invoices WHERE invoice_no=?",(ino,))\n            if not ii.empty:\n                inv=ii.iloc[0].to_dict(); ss=query("SELECT * FROM reservations WHERE reservation_id=?",(inv['reservation_id'],)); pdf=build_invoice_pdf(inv,ss.iloc[0].to_dict()) if not ss.empty else None\n                if pdf: st.download_button('🖨️ Print / Download Final Invoice',pdf,f\"{ino}_Final_Invoice.pdf\",'application/pdf',use_container_width=True,key='latest_inv')\n                else: st.error('Install reportlab: pip install reportlab')\n        regs=query("SELECT invoice_no,invoice_date,reservation_id,guest_name,room_no,gross_amount,deposit_amount,final_payment,balance_due,status FROM guest_invoices ORDER BY created_at DESC")\n        if not regs.empty:\n            st.markdown('#### Reprint previous invoice'); st.dataframe(regs,use_container_width=True,hide_index=True); rno=st.selectbox('Invoice to reprint',regs['invoice_no'].tolist(),key='rpi'); ii=query("SELECT * FROM guest_invoices WHERE invoice_no=?",(rno,)); ss=query("SELECT * FROM reservations WHERE reservation_id=?",(ii.iloc[0]['reservation_id'],)) if not ii.empty else pd.DataFrame(); pdf=build_invoice_pdf(ii.iloc[0].to_dict(),ss.iloc[0].to_dict()) if not ii.empty and not ss.empty else None\n            if pdf: st.download_button('Reprint Selected Invoice',pdf,f\"{rno}_Final_Invoice.pdf\",'application/pdf',use_container_width=True,key=f'rp_{rno}')\n'''

def main():
    if not TARGET.exists():
        raise SystemExit(f'File not found: {TARGET.resolve()}')
    source=TARGET.read_text(encoding='utf-8')
    backup=TARGET.with_suffix(TARGET.suffix+'.backup_before_billing')
    shutil.copy2(TARGET,backup)
    if 'REPORTLAB_AVAILABLE' not in source:
        anchor='from pathlib import Path\n'
        if anchor not in source: raise SystemExit('Import anchor not found.')
        source=source.replace(anchor,anchor+IMPORTS,1)
    if 'def migrate_guest_billing():' not in source:
        anchor='migrate_supplier_invoices()\n'
        if anchor not in source: anchor='init_db()\n'
        if anchor not in source: raise SystemExit('Database anchor not found.')
        source=source.replace(anchor,anchor+HELPERS,1)
    pattern=re.compile(r'# ---------------- Front Desk ----------------\s*elif page == "Front Desk":.*?(?=# ---------------- (?:Rooms|Restaurant POS|Housekeeping|Inventory|Purchasing|Maintenance|Payments|Expenses|Finance|AI|Reports|User Access) ----------------)',re.S)
    m=pattern.search(source)
    if not m: raise SystemExit('Front Desk section not found. Use your latest app.py.')
    source=source[:m.start()]+FRONT+'\n\n'+source[m.end():]
    TARGET.write_text(source,encoding='utf-8')
    req=TARGET.parent/'requirements.txt'
    txt=req.read_text(encoding='utf-8') if req.exists() else 'streamlit\npandas\nopenpyxl\n'
    if 'reportlab' not in txt.lower(): txt=txt.rstrip()+'\nreportlab>=4.0\n'
    req.write_text(txt,encoding='utf-8')
    print('Updated:',TARGET.resolve())
    print('Backup:',backup.resolve())
    print('Added advance receipt at check-in and final PDF invoice at check-out.')

if __name__=='__main__':
    main()
